import fs from 'fs';
import path from 'path';

const baseDir = 'open-source/gnosis/lean/Lean/ForkRaceFoldTheorems';

function findTheorems(dir, results = {}) {
    const files = fs.readdirSync(dir);
    for (const file of files) {
        const fullPath = path.join(dir, file);
        if (fs.statSync(fullPath).isDirectory()) {
            findTheorems(fullPath, results);
        } else if (file.endsWith('.lean')) {
            const content = fs.readFileSync(fullPath, 'utf8');
            const matches = content.matchAll(/^[ \t]*(theorem|lemma|def|noncomputable def|instance|class|structure|inductive)\s+([a-zA-Z0-9_']+)/gm);
            const relPath = path.relative('open-source/gnosis/lean/Lean', fullPath);
            const fileName = relPath.replace(/\//g, '.').replace('.lean', '');
            
            for (const match of matches) {
                const name = `${fileName}.${match[2]}`;
                results[name] = true;
            }
        }
    }
    return results;
}

const existingTheorems = findTheorems(baseDir);
console.log(JSON.stringify(existingTheorems, null, 2));
